template.script:
(function () {
    'use strict';

    var pieChart = null;
    var PIE_COLORS = ['#64b5f6', '#ffca28', '#66bb6a', '#ef5350', '#ab47bc'];
    var PIE_LABELS = ['Draft', 'In Auction', 'Sold', 'Unsold'];

    /* ─── helpers ─── */
    function fmt(n) { return (n !== null && n !== undefined) ? Number(n).toLocaleString() : '—'; }
    function pct(spent, total) {
        if (!total) return 0;
        return Math.min(100, Math.round(spent / total * 100));
    }
    function badgeClass(left, total) {
        if (!total) return 'badge-green';
        var p = left / total;
        if (p > 0.4) return 'badge-green';
        if (p > 0.15) return 'badge-yellow';
        return 'badge-red';
    }
    function progressColor(spent, total) {
        if (!total) return '#66bb6a';
        var p = spent / total;
        if (p < 0.5) return '#66bb6a';
        if (p < 0.8) return '#ffca28';
        return '#ef5350';
    }
    function imgOrPlaceholder(url, cssClass, placeholder, isTeam) {
        if (url) {
            return '<img src="' + url + '" class="' + cssClass + '" onerror="this.style.display=\'none\'">';
        }
        var ph = isTeam ? '🏏' : '👤';
        return '<div class="' + placeholder + '">' + ph + '</div>';
    }

    /* ─── Pie Chart ─── */
    function renderPie(counts) {
        var data = [counts.draft, counts.auction, counts.sold, counts.unsold];
        var ctx = document.getElementById('playerPieChart').getContext('2d');

        if (pieChart) {
            pieChart.data.datasets[0].data = data;
            pieChart.update();
        } else {
            pieChart = new Chart(ctx, {
                type: 'doughnut',
                data: {
                    labels: PIE_LABELS,
                    datasets: [{
                        data: data,
                        backgroundColor: PIE_COLORS,
                        borderColor: 'rgba(255,255,255,.15)',
                        borderWidth: 2,
                        hoverOffset: 8,
                    }],
                },
                options: {
                    cutout: '62%',
                    plugins: {
                        legend: { display: false },
                        tooltip: {
                            callbacks: {
                                label: function(ctx) {
                                    return ' ' + ctx.label + ': ' + ctx.parsed;
                                }
                            }
                        }
                    },
                    animation: { duration: 700 },
                }
            });
        }

        // custom legend
        var leg = document.getElementById('pie-legend');
        leg.innerHTML = PIE_LABELS.map(function(lbl, i) {
            return '<div class="dash-legend-item">' +
                '<span class="dash-legend-dot" style="background:' + PIE_COLORS[i] + '"></span>' +
                '<span>' + lbl + ' (' + data[i] + ')</span>' +
                '</div>';
        }).join('');
    }

    /* ─── Summary boxes ─── */
    function renderSummary(counts) {
        document.getElementById('stat-draft').textContent   = fmt(counts.draft);
        document.getElementById('stat-auction').textContent = fmt(counts.auction);
        document.getElementById('stat-sold').textContent    = fmt(counts.sold);
        document.getElementById('stat-unsold').textContent  = fmt(counts.unsold);
        document.getElementById('stat-total').textContent   =
            fmt(counts.draft + counts.auction + counts.sold + counts.unsold);
    }

    /* ─── Top-bid cards ─── */
    function renderTopBidCards(teams) {
        var container = document.getElementById('top-bid-container');
        if (!teams || !teams.length) {
            container.innerHTML = '<p style="color:rgba(255,255,255,.4);padding:1rem">No team data yet.</p>';
            return;
        }
        container.innerHTML = teams.map(function(team) {
            var teamLogo = imgOrPlaceholder(team.logo_url, 'dash-bid-team-logo', 'dash-bid-team-logo-placeholder', true);
            var playerSection;
            if (team.top_player) {
                var tp = team.top_player;
                var playerPhoto = imgOrPlaceholder(tp.photo_url, 'dash-bid-player-photo', 'dash-bid-player-photo-placeholder', false);
                playerSection =
                    '<div class="dash-bid-player-section">' +
                        playerPhoto +
                        '<div class="dash-bid-player-info">' +
                            '<div class="dash-bid-player-name">' + tp.name + '</div>' +
                            '<div class="dash-bid-player-role">' + (tp.role || '—') + '</div>' +
                            '<div class="dash-bid-points">' + fmt(tp.points) + ' pts</div>' +
                        '</div>' +
                    '</div>';
            } else {
                playerSection = '<div class="dash-bid-no-player">No players acquired yet</div>';
            }
            return '<div class="dash-bid-card">' +
                '<div class="dash-bid-team-header">' +
                    teamLogo +
                    '<span class="dash-bid-team-name">' + team.name + '</span>' +
                '</div>' +
                playerSection +
            '</div>';
        }).join('');
    }

    /* ─── Team stats table ─── */
    function renderTeamTable(teams) {
        var tbody = document.getElementById('team-stats-body');
        if (!teams || !teams.length) {
            tbody.innerHTML = '<tr><td colspan="8" class="dash-loading">No team data yet.</td></tr>';
            return;
        }
        tbody.innerHTML = teams.map(function(team) {
            var spent = team.total_points - team.remaining_points;
            var barPct  = pct(spent, team.total_points);
            var barClr  = progressColor(spent, team.total_points);
            var bc      = badgeClass(team.remaining_points, team.total_points);
            var logo    = imgOrPlaceholder(team.logo_url, 'dash-table-logo', 'dash-table-logo-placeholder', true);

            return '<tr>' +
                '<td><div class="dash-team-cell">' + logo +
                    '<span class="dash-team-name-text">' + team.name + '</span></div></td>' +
                '<td>' + (team.manager || '—') + '</td>' +
                '<td style="text-align:center">' + team.players_bought + '</td>' +
                '<td style="text-align:center">' + team.remaining_players + '</td>' +
                '<td>' + fmt(team.total_points) + '</td>' +
                '<td>' +
                    fmt(spent) +
                    '<div class="dash-progress-wrap"><div class="dash-progress-bar" style="width:' + barPct + '%;background:' + barClr + '"></div></div>' +
                '</td>' +
                '<td><span class="badge-points-left ' + bc + '">' + fmt(team.remaining_points) + '</span></td>' +
                '<td><span class="dash-max-call">' + fmt(team.max_call) + '</span></td>' +
            '</tr>';
        }).join('');
    }

    /* ─── Main loader ─── */
    window.loadDashboard = function() {
        fetch('/auction/dashboard/data', { cache: 'no-store' })
            .then(function(r) { return r.json(); })
            .then(function(data) {
                renderPie(data.player_counts);
                renderSummary(data.player_counts);
                renderTopBidCards(data.teams);
                renderTeamTable(data.teams);
            })
            .catch(function(err) {
                console.error('Dashboard load failed', err);
            });
    };

    /* ─── Auto-refresh every 30 s ─── */
    loadDashboard();
    var _dashTimer = setInterval(loadDashboard, 30000);
    document.addEventListener('visibilitychange', function() {
        if (document.hidden) {
            clearInterval(_dashTimer);
            _dashTimer = null;
        } else {
            loadDashboard();
            _dashTimer = setInterval(loadDashboard, 30000);
        }
    });
})();
